import type { MidiDeviceInfo, MidiEvent, DeviceCapabilities } from "./types";
import { newCapabilities } from "./types";
import { ClockSync } from "./clock";

type EventListener = (ev: MidiEvent) => void;
type DevicesListener = (devices: MidiDeviceInfo[]) => void;

/**
 * Gestor de entrada MIDI.
 *
 * - Parsea TODOS los tipos de mensaje del canal de voz, conservando bytes crudos.
 * - Note On con velocidad 0 se normaliza a Note Off (comportamiento MIDI estándar).
 * - Detecta qué transmite realmente el dispositivo (release velocity, aftertouch,
 *   medio pedal…) observando el tráfico, sin suposiciones.
 * - Reconexión automática vía statechange.
 * - Filtro de canal opcional (modo Omni por defecto).
 */
export class MidiManager {
  private access: MIDIAccess | null = null;
  private listeners = new Set<EventListener>();
  private deviceListeners = new Set<DevicesListener>();
  private clock: ClockSync;
  readonly capabilities = new Map<string, DeviceCapabilities>();
  /** null = Omni (todos los canales). */
  channelFilter: number | null = null;
  /** Dispositivo seleccionado; null = todos. */
  deviceFilter: string | null = null;
  /** Compensación de latencia de entrada, en ms (se resta al timestamp). */
  inputLatencyMs = 0;

  supported = typeof navigator !== "undefined" && "requestMIDIAccess" in navigator;
  lastError: string | null = null;

  constructor(ctx: AudioContext) {
    this.clock = new ClockSync(ctx);
    this.clock.start();
  }

  async init(): Promise<boolean> {
    if (!this.supported) {
      this.lastError = "Web MIDI no está disponible en este navegador.";
      return false;
    }
    try {
      this.access = await navigator.requestMIDIAccess({ sysex: false });
    } catch (e) {
      this.lastError = `Permiso MIDI denegado o error: ${String(e)}`;
      return false;
    }
    this.access.onstatechange = () => this.rewire();
    this.rewire();
    return true;
  }

  private rewire(): void {
    if (!this.access) return;
    for (const input of this.access.inputs.values()) {
      input.onmidimessage = (msg) => this.onMessage(input.id, msg);
      if (!this.capabilities.has(input.id)) {
        this.capabilities.set(input.id, newCapabilities());
      }
    }
    this.notifyDevices();
  }

  devices(): MidiDeviceInfo[] {
    if (!this.access) return [];
    return [...this.access.inputs.values()].map((i) => ({
      id: i.id,
      name: i.name ?? "(sin nombre)",
      manufacturer: i.manufacturer ?? "",
      state: i.state,
    }));
  }

  onEvent(fn: EventListener): () => void {
    this.listeners.add(fn);
    return () => this.listeners.delete(fn);
  }

  onDevicesChanged(fn: DevicesListener): () => void {
    this.deviceListeners.add(fn);
    return () => this.deviceListeners.delete(fn);
  }

  private notifyDevices(): void {
    const d = this.devices();
    for (const fn of this.deviceListeners) fn(d);
  }

  /** Inyecta un evento sintético (teclado táctil/QWERTY, tests). */
  inject(partial: Omit<MidiEvent, "hrTime" | "audioTime" | "deviceId" | "raw"> & { raw?: Uint8Array }): void {
    const hr = performance.now();
    const ev: MidiEvent = {
      raw: partial.raw ?? new Uint8Array(0),
      hrTime: hr,
      audioTime: this.clock.toAudioTime(hr),
      deviceId: "__internal__",
      ...partial,
    };
    this.dispatch(ev);
  }

  private onMessage(deviceId: string, msg: MIDIMessageEvent): void {
    const data = msg.data;
    if (!data || data.length === 0) return;
    const hr = msg.timeStamp - this.inputLatencyMs;
    const ev = parseMidi(data, hr, this.clock.toAudioTime(hr), deviceId);
    this.learnCapabilities(deviceId, ev);

    if (this.deviceFilter !== null && deviceId !== this.deviceFilter) return;
    if (
      this.channelFilter !== null &&
      ev.channel >= 0 &&
      ev.channel !== this.channelFilter
    ) {
      return;
    }
    this.dispatch(ev);
  }

  private dispatch(ev: MidiEvent): void {
    for (const fn of this.listeners) fn(ev);
  }

  private learnCapabilities(deviceId: string, ev: MidiEvent): void {
    let cap = this.capabilities.get(deviceId);
    if (!cap) {
      cap = newCapabilities();
      this.capabilities.set(deviceId, cap);
    }
    if (ev.channel >= 0) cap.channelsSeen.add(ev.channel);
    switch (ev.kind) {
      case "noteOff":
        if ((ev.releaseVelocity ?? 0) > 0 && ev.releaseVelocity !== 64) {
          cap.sendsReleaseVelocity = true;
        }
        break;
      case "channelPressure":
        cap.sendsChannelPressure = true;
        break;
      case "polyAftertouch":
        cap.sendsPolyAftertouch = true;
        break;
      case "pitchBend":
        if (ev.bend14 !== 0) cap.sendsPitchBend = true;
        break;
      case "controlChange":
        cap.seenControllers.set(ev.controller!, ev.value!);
        if (ev.controller === 64 && ev.value! > 0 && ev.value! < 127) {
          cap.continuousSustain = true;
        }
        break;
    }
  }
}

/** Parsea un mensaje MIDI crudo a MidiEvent. Exportado para tests. */
export function parseMidi(
  data: Uint8Array,
  hrTime: number,
  audioTime: number,
  deviceId: string,
): MidiEvent {
  const status = data[0];
  const base = { raw: data.slice(), hrTime, audioTime, deviceId };

  if (status >= 0xf0) {
    return { ...base, kind: "system", channel: -1 };
  }
  const type = status & 0xf0;
  const channel = status & 0x0f;

  switch (type) {
    case 0x90: {
      const note = data[1], vel = data[2];
      if (vel === 0) {
        // Note On con velocidad 0 = Note Off (regla MIDI, crítica para no dejar notas atascadas).
        return { ...base, kind: "noteOff", channel, note, releaseVelocity: 0 };
      }
      return { ...base, kind: "noteOn", channel, note, velocity: vel };
    }
    case 0x80:
      return { ...base, kind: "noteOff", channel, note: data[1], releaseVelocity: data[2] };
    case 0xa0:
      return { ...base, kind: "polyAftertouch", channel, note: data[1], value: data[2] };
    case 0xb0:
      return { ...base, kind: "controlChange", channel, controller: data[1], value: data[2] };
    case 0xc0:
      return { ...base, kind: "programChange", channel, value: data[1] };
    case 0xd0:
      return { ...base, kind: "channelPressure", channel, value: data[1] };
    case 0xe0: {
      // Resolución completa de 14 bits: LSB + MSB.
      const bend14 = (data[1] | (data[2] << 7)) - 8192;
      return { ...base, kind: "pitchBend", channel, bend14 };
    }
    default:
      return { ...base, kind: "unknown", channel };
  }
}
