import type { MidiManager } from "../midi/manager";
import type { NoteTracker } from "../midi/noteTracker";
import type { MasterBus } from "../audio/masterBus";
import type { EnginePreset } from "../audio/engines/types";
import type { Settings } from "../state/settings";
import { TouchKeyboard } from "./keyboard";
import { DiagnosticsView } from "./monitor";

export interface AppDeps {
  midi: MidiManager;
  tracker: NoteTracker;
  master: MasterBus;
  presets: EnginePreset[];
  settings: Settings;
  currentPreset: () => EnginePreset;
  loadPreset: (p: EnginePreset) => void;
  onSettingsChanged: () => void;
  onFirstGesture: () => void;
  runTest: (name: "chord" | "sequence" | "pedal" | "poly") => void;
  voiceCount: () => number;
}

type Tab = "tocar" | "presets" | "diag" | "ajustes";

export class App {
  private views = new Map<Tab, HTMLElement>();
  private diag: DiagnosticsView;
  private active: Tab = "tocar";
  private midiDot!: HTMLElement;
  private deviceEl!: HTMLElement;
  private presetEl!: HTMLElement;
  private voicesEl!: HTMLElement;
  private susBar!: HTMLElement;
  private meterEl!: HTMLElement;
  private midiFlash = 0;

  constructor(private root: HTMLElement, private d: AppDeps) {
    this.diag = new DiagnosticsView(d.midi, d.tracker, d.runTest);
    this.build();
    d.midi.onEvent(() => (this.midiFlash = performance.now()));
    d.midi.onDevicesChanged(() => this.refreshHeader());
    requestAnimationFrame(() => this.tick());
  }

  private build(): void {
    this.root.innerHTML = `
      <header class="status">
        <div class="brand">ONDA</div>
        <div class="lcd mono">
          <span class="midi-dot" title="Actividad MIDI"></span>
          <span class="device"></span>
          <span class="preset"></span>
          <span class="voices"></span>
        </div>
        <div class="sus-wrap" title="Pedal sustain">
          <div class="sus-bar"></div>
        </div>
        <div class="meter-wrap"><div class="meter"></div></div>
        <button class="panic" title="Corta todo el sonido inmediatamente">PÁNICO</button>
      </header>
      <main></main>
      <nav class="tabs">
        <button data-tab="tocar" class="on">Tocar</button>
        <button data-tab="presets">Presets</button>
        <button data-tab="diag">Diagnóstico</button>
        <button data-tab="ajustes">Ajustes</button>
      </nav>`;

    this.midiDot = this.root.querySelector(".midi-dot")!;
    this.deviceEl = this.root.querySelector(".device")!;
    this.presetEl = this.root.querySelector(".preset")!;
    this.voicesEl = this.root.querySelector(".voices")!;
    this.susBar = this.root.querySelector(".sus-bar")!;
    this.meterEl = this.root.querySelector(".meter")!;
    this.root.querySelector(".panic")!.addEventListener("click", () => this.d.tracker.panic());

    const main = this.root.querySelector("main")!;
    this.views.set("tocar", this.buildPlayView());
    this.views.set("presets", this.buildPresetsView());
    this.views.set("diag", this.diag.el);
    this.views.set("ajustes", this.buildSettingsView());
    for (const v of this.views.values()) main.append(v);

    this.root.querySelectorAll<HTMLButtonElement>("[data-tab]").forEach((b) =>
      b.addEventListener("click", () => this.show(b.dataset.tab as Tab)),
    );
    this.show("tocar");
    this.refreshHeader();
  }

  private show(tab: Tab): void {
    this.active = tab;
    for (const [k, v] of this.views) v.classList.toggle("hidden", k !== tab);
    this.root.querySelectorAll<HTMLButtonElement>("[data-tab]").forEach((b) =>
      b.classList.toggle("on", b.dataset.tab === tab),
    );
    this.diag.setVisible(tab === "diag");
    this.d.master.suspendMeter(false);
  }

  private buildPlayView(): HTMLElement {
    const v = document.createElement("div");
    v.className = "view play";
    const kb = new TouchKeyboard(this.d.midi, this.d.onFirstGesture);
    const info = document.createElement("div");
    info.className = "play-info";
    info.innerHTML = `<p class="hint">Conecta el GO:PIANO por USB y toca. Sin teclado físico,
      usa las teclas de abajo o el teclado del ordenador (A–K, Z/X octava, espacio = sustain).</p>`;
    v.append(info, kb.el);
    return v;
  }

  private buildPresetsView(): HTMLElement {
    const v = document.createElement("div");
    v.className = "view presets";
    v.innerHTML = `<h2>Presets</h2><p class="hint">Motor sustractivo · Etapa 1.
      El piano multisampleado y el resto de motores llegan en la Etapa 2.</p>`;
    const list = document.createElement("div");
    list.className = "preset-list";
    for (const p of this.d.presets) {
      const card = document.createElement("button");
      card.className = "preset-card";
      card.innerHTML = `<strong>${p.name}</strong>
        <span class="desc">${p.description ?? ""}</span>
        <span class="tags mono">${(p.tags ?? []).join(" · ")} · ${p.polyphony} voces</span>`;
      card.addEventListener("click", () => {
        this.d.loadPreset(p);
        list.querySelectorAll(".preset-card").forEach((c) => c.classList.remove("on"));
        card.classList.add("on");
        this.refreshHeader();
      });
      if (p.name === this.d.settings.presetName) card.classList.add("on");
      list.append(card);
    }
    v.append(list);
    return v;
  }

  private buildSettingsView(): HTMLElement {
    const s = this.d.settings;
    const v = document.createElement("div");
    v.className = "view settings";
    v.innerHTML = `<h2>Ajustes</h2>`;

    const deviceSel = selectRow(v, "Dispositivo MIDI", []);
    const refreshDevices = () => {
      const devs = this.d.midi.devices();
      deviceSel.innerHTML =
        `<option value="">Todos</option>` +
        devs.map((d) => `<option value="${d.id}">${d.name}</option>`).join("");
      deviceSel.value = s.deviceId ?? "";
    };
    refreshDevices();
    this.d.midi.onDevicesChanged(refreshDevices);
    deviceSel.addEventListener("change", () => {
      s.deviceId = deviceSel.value || null;
      this.d.onSettingsChanged();
    });

    const chSel = selectRow(v, "Canal MIDI", [
      ["", "Omni (todos)"],
      ...Array.from({ length: 16 }, (_, i) => [String(i), `Canal ${i + 1}`] as [string, string]),
    ]);
    chSel.value = s.channel === null ? "" : String(s.channel);
    chSel.addEventListener("change", () => {
      s.channel = chSel.value === "" ? null : Number(chSel.value);
      this.d.onSettingsChanged();
    });

    const trans = rangeRow(v, "Transposición", -24, 24, 1, s.transpose, (x) => `${x > 0 ? "+" : ""}${x} st`);
    trans.addEventListener("input", () => {
      s.transpose = Number(trans.value);
      this.d.onSettingsChanged();
    });

    const curve = selectRow(v, "Curva de velocidad", [
      ["linear", "Lineal"],
      ["soft", "Suave (más fácil tocar fuerte)"],
      ["hard", "Dura (más rango expresivo)"],
    ]);
    curve.value = s.velocityCurve;
    curve.addEventListener("change", () => {
      s.velocityCurve = curve.value as Settings["velocityCurve"];
      this.d.onSettingsChanged();
    });

    const vmin = rangeRow(v, "Velocidad mínima", 0, 0.5, 0.01, s.velocityMin, (x) => `${Math.round(x * 127)}`);
    vmin.addEventListener("input", () => {
      s.velocityMin = Number(vmin.value);
      this.d.onSettingsChanged();
    });
    const vmax = rangeRow(v, "Velocidad máxima", 0.5, 1, 0.01, s.velocityMax, (x) => `${Math.round(x * 127)}`);
    vmax.addEventListener("input", () => {
      s.velocityMax = Number(vmax.value);
      this.d.onSettingsChanged();
    });

    const lat = rangeRow(v, "Compensación de latencia de entrada", 0, 60, 1, s.inputLatencyMs, (x) => `${x} ms`);
    lat.addEventListener("input", () => {
      s.inputLatencyMs = Number(lat.value);
      this.d.onSettingsChanged();
    });

    const timeout = rangeRow(v, "Timeout de seguridad de notas (0 = sin límite)", 0, 300, 10, s.safetyTimeoutSec, (x) =>
      x === 0 ? "desactivado" : `${x} s`,
    );
    timeout.addEventListener("input", () => {
      s.safetyTimeoutSec = Number(timeout.value);
      this.d.onSettingsChanged();
    });

    const note = document.createElement("p");
    note.className = "hint";
    note.textContent =
      "Consejo Android: instala la app desde el menú del navegador (“Añadir a pantalla de inicio”) para usarla a pantalla completa y sin conexión.";
    v.append(note);
    return v;
  }

  private refreshHeader(): void {
    const devs = this.d.midi.devices().filter((x) => x.state === "connected");
    this.deviceEl.textContent = devs.length ? devs.map((x) => x.name).join(", ") : "sin MIDI";
    this.presetEl.textContent = this.d.currentPreset().name;
  }

  private tick(): void {
    // Punto de actividad MIDI: se apaga 150 ms después del último evento.
    this.midiDot.classList.toggle("active", performance.now() - this.midiFlash < 150);
    this.voicesEl.textContent = `${this.d.voiceCount()}v`;
    this.susBar.style.height = `${(this.d.tracker.sustainValue(0) / 127) * 100}%`;

    const { peak } = this.d.master.levels();
    const db = 20 * Math.log10(Math.max(peak, 1e-5));
    const pct = Math.max(0, Math.min(1, (db + 48) / 48));
    this.meterEl.style.width = `${pct * 100}%`;
    this.meterEl.classList.toggle("hot", db > -3 || this.d.master.gainReductionDb() < -1);

    if (this.active === "tocar" || this.active === "diag" || document.visibilityState === "visible") {
      requestAnimationFrame(() => this.tick());
    } else {
      setTimeout(() => this.tick(), 300);
    }
  }
}

function selectRow(parent: HTMLElement, label: string, opts: [string, string][]): HTMLSelectElement {
  const row = document.createElement("label");
  row.className = "srow";
  row.innerHTML = `<span>${label}</span>`;
  const sel = document.createElement("select");
  sel.innerHTML = opts.map(([v, t]) => `<option value="${v}">${t}</option>`).join("");
  row.append(sel);
  parent.append(row);
  return sel;
}

function rangeRow(
  parent: HTMLElement,
  label: string,
  min: number,
  max: number,
  step: number,
  value: number,
  fmt: (x: number) => string,
): HTMLInputElement {
  const row = document.createElement("label");
  row.className = "srow";
  const out = document.createElement("output");
  out.className = "mono";
  out.textContent = fmt(value);
  row.innerHTML = `<span>${label}</span>`;
  const input = document.createElement("input");
  input.type = "range";
  input.min = String(min);
  input.max = String(max);
  input.step = String(step);
  input.value = String(value);
  input.addEventListener("input", () => (out.textContent = fmt(Number(input.value))));
  row.append(input, out);
  parent.append(row);
  return input;
}
