import type { MidiEvent } from "../midi/types";
import type { MidiManager } from "../midi/manager";
import type { NoteTracker } from "../midi/noteTracker";
import { audioInfo } from "../audio/context";

const NOTE_NAMES = ["C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "A#", "B"];
export function noteName(n: number): string {
  return `${NOTE_NAMES[n % 12]}${Math.floor(n / 12) - 1}`;
}

function describe(ev: MidiEvent): string {
  switch (ev.kind) {
    case "noteOn":
      return `Note On   ${noteName(ev.note!)} vel ${ev.velocity}`;
    case "noteOff":
      return `Note Off  ${noteName(ev.note!)} rel ${ev.releaseVelocity}`;
    case "controlChange": {
      const names: Record<number, string> = {
        1: "Mod", 2: "Breath", 7: "Vol", 11: "Expr",
        64: "Sustain", 66: "Sostenuto", 67: "Soft",
        120: "AllSoundOff", 121: "ResetCtrl", 123: "AllNotesOff",
      };
      const nm = names[ev.controller!] ?? `CC${ev.controller}`;
      return `CC        ${nm} = ${ev.value}`;
    }
    case "pitchBend":
      return `PitchBend ${ev.bend14! >= 0 ? "+" : ""}${ev.bend14}`;
    case "channelPressure":
      return `ChanPress ${ev.value}`;
    case "polyAftertouch":
      return `PolyAT    ${noteName(ev.note!)} = ${ev.value}`;
    case "programChange":
      return `Program   ${ev.value}`;
    case "system":
      return `Sistema   [${hex(ev.raw)}]`;
    default:
      return `Desconocido [${hex(ev.raw)}]`;
  }
}

function hex(raw: Uint8Array): string {
  return [...raw].map((b) => b.toString(16).padStart(2, "0")).join(" ");
}

/** Monitor MIDI + diagnóstico completo. */
export class DiagnosticsView {
  readonly el: HTMLElement;
  private log: MidiEvent[] = [];
  private logEl!: HTMLElement;
  private notesEl!: HTMLElement;
  private capsEl!: HTMLElement;
  private sysEl!: HTMLElement;
  private counters = { events: 0, notesOn: 0 };
  private visible = false;

  constructor(
    private midi: MidiManager,
    private tracker: NoteTracker,
    private runTest: (name: "chord" | "sequence" | "pedal" | "poly") => void,
  ) {
    this.el = document.createElement("div");
    this.el.className = "view diag";
    this.build();
    midi.onEvent((ev) => this.push(ev));
    setInterval(() => this.visible && this.refresh(), 400);
  }

  setVisible(v: boolean): void {
    this.visible = v;
    if (v) this.refresh();
  }

  private build(): void {
    this.el.innerHTML = `
      <h2>Diagnóstico</h2>
      <section><h3>Sistema</h3><div class="sys mono"></div></section>
      <section><h3>Capacidades detectadas del dispositivo</h3>
        <p class="hint">Se detectan observando el tráfico real, sin suposiciones.</p>
        <div class="caps mono"></div></section>
      <section><h3>Notas activas</h3><div class="notes mono"></div></section>
      <section><h3>Pruebas sin teclado</h3>
        <div class="row">
          <button data-t="chord">Acorde</button>
          <button data-t="sequence">Secuencia</button>
          <button data-t="pedal">Pedal</button>
          <button data-t="poly">Polifonía</button>
        </div></section>
      <section><h3>Monitor MIDI</h3><div class="log mono"></div>
        <div class="row">
          <button class="clear">Limpiar</button>
          <button class="export">Exportar informe</button>
        </div></section>`;
    this.logEl = this.el.querySelector(".log")!;
    this.notesEl = this.el.querySelector(".notes")!;
    this.capsEl = this.el.querySelector(".caps")!;
    this.sysEl = this.el.querySelector(".sys")!;
    this.el.querySelectorAll<HTMLButtonElement>("[data-t]").forEach((b) =>
      b.addEventListener("click", () => this.runTest(b.dataset.t as never)),
    );
    this.el.querySelector(".clear")!.addEventListener("click", () => {
      this.log = [];
      this.refresh();
    });
    this.el.querySelector(".export")!.addEventListener("click", () => this.exportReport());
  }

  private push(ev: MidiEvent): void {
    this.counters.events++;
    if (ev.kind === "noteOn") this.counters.notesOn++;
    this.log.push(ev);
    if (this.log.length > 60) this.log.shift();
    if (this.visible) this.renderLog();
  }

  private refresh(): void {
    const a = audioInfo();
    const sw = "serviceWorker" in navigator;
    this.sysEl.innerHTML = [
      `Web MIDI: ${this.midi.supported ? "disponible" : "NO disponible"}`,
      this.midi.lastError ? `Error MIDI: ${this.midi.lastError}` : null,
      `Audio: ${a.state} · ${a.sampleRate} Hz`,
      `Latencia base: ${fmtMs(a.baseLatency)} · salida: ${fmtMs(a.outputLatency)}`,
      `Service Worker: ${sw ? "soportado" : "no soportado"}`,
      `Eventos recibidos: ${this.counters.events} (${this.counters.notesOn} Note On)`,
    ]
      .filter(Boolean)
      .map((l) => `<div>${l}</div>`)
      .join("");

    const caps = [...this.midi.capabilities.entries()].filter(([id]) => id !== "__internal__");
    this.capsEl.innerHTML =
      caps.length === 0
        ? `<div class="hint">Aún no se ha recibido tráfico de ningún dispositivo.</div>`
        : caps
            .map(([id, c]) => {
              const dev = this.midi.devices().find((d) => d.id === id);
              const ccs = [...c.seenControllers.keys()].sort((x, y) => x - y).join(", ") || "ninguno";
              return `<div class="cap">
                <strong>${dev?.name ?? id}</strong>
                <div>Release velocity: ${yn(c.sendsReleaseVelocity)} · Aftertouch canal: ${yn(c.sendsChannelPressure)} · Aftertouch poli: ${yn(c.sendsPolyAftertouch)}</div>
                <div>Pitch bend: ${yn(c.sendsPitchBend)} · Medio pedal: ${yn(c.continuousSustain)} · Canales: ${[...c.channelsSeen].map((x) => x + 1).join(", ") || "—"}</div>
                <div>CCs vistos: ${ccs}</div></div>`;
            })
            .join("");

    const notes = this.tracker.activeNotes();
    this.notesEl.innerHTML =
      notes.length === 0
        ? `<div class="hint">Ninguna. (Si oyes sonido sin notas aquí, son colas de release: correcto.)</div>`
        : notes
            .map((n) => {
              const st = n.state === "held" ? "pulsada" : n.state === "sustained" ? "pedal" : "sostenuto";
              return `<div>${noteName(n.note).padEnd(4)} vel ${(n.velocity * 127) | 0}  [${st}${n.inSostenuto && n.state === "held" ? "+sost" : ""}]</div>`;
            })
            .join("");
    this.renderLog();
  }

  private renderLog(): void {
    this.logEl.innerHTML = this.log
      .slice(-30)
      .reverse()
      .map((ev) => `<div><span class="t">${ev.audioTime.toFixed(3)}s</span> ch${ev.channel + 1} ${describe(ev)}</div>`)
      .join("");
  }

  private exportReport(): void {
    const a = audioInfo();
    const report = {
      app: "Onda Studio (Etapa 1)",
      fecha: new Date().toISOString(),
      userAgent: navigator.userAgent,
      audio: a,
      webMidi: this.midi.supported,
      errorMidi: this.midi.lastError,
      dispositivos: this.midi.devices(),
      capacidades: [...this.midi.capabilities.entries()].map(([id, c]) => ({
        id,
        releaseVelocity: c.sendsReleaseVelocity,
        channelPressure: c.sendsChannelPressure,
        polyAftertouch: c.sendsPolyAftertouch,
        pitchBend: c.sendsPitchBend,
        medioPedal: c.continuousSustain,
        ccsVistos: Object.fromEntries(c.seenControllers),
        canales: [...c.channelsSeen],
      })),
      contadores: this.counters,
      ultimosEventos: this.log.slice(-60).map((e) => ({
        t: e.audioTime,
        raw: [...e.raw],
        kind: e.kind,
      })),
    };
    const blob = new Blob([JSON.stringify(report, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `onda-diagnostico-${Date.now()}.json`;
    link.click();
    setTimeout(() => URL.revokeObjectURL(url), 5000);
  }
}

function yn(b: boolean): string {
  return b ? "sí" : "no detectado";
}
function fmtMs(s: number | null): string {
  return s === null ? "—" : `${(s * 1000).toFixed(1)} ms`;
}
