/**
 * Ajustes de usuario, persistidos en localStorage (ligeros y síncronos).
 * IndexedDB llegará en la Etapa 4 para proyectos/clips/presets personales,
 * que son datos grandes y estructurados.
 */
export interface Settings {
  deviceId: string | null;
  channel: number | null; // null = Omni
  transpose: number;
  velocityCurve: "linear" | "soft" | "hard";
  velocityMin: number; // 0–1
  velocityMax: number; // 0–1
  safetyTimeoutSec: number; // 0 = desactivado
  inputLatencyMs: number;
  presetName: string;
}

const KEY = "onda.settings.v1";

const DEFAULTS: Settings = {
  deviceId: null,
  channel: null,
  transpose: 0,
  velocityCurve: "linear",
  velocityMin: 0,
  velocityMax: 1,
  safetyTimeoutSec: 0,
  inputLatencyMs: 0,
  presetName: "Nocturno EP",
};

export function loadSettings(): Settings {
  try {
    const raw = localStorage.getItem(KEY);
    if (raw) return { ...DEFAULTS, ...JSON.parse(raw) };
  } catch {
    /* datos corruptos → valores por defecto */
  }
  return { ...DEFAULTS };
}

export function saveSettings(s: Settings): void {
  try {
    localStorage.setItem(KEY, JSON.stringify(s));
  } catch {
    /* almacenamiento lleno o bloqueado: no es crítico */
  }
}

/** Construye la función de curva de velocidad según los ajustes. */
export function buildVelocityCurve(s: Settings): (v: number) => number {
  const shape =
    s.velocityCurve === "soft"
      ? (v: number) => Math.pow(v, 0.6)
      : s.velocityCurve === "hard"
        ? (v: number) => Math.pow(v, 1.7)
        : (v: number) => v;
  const min = Math.min(s.velocityMin, s.velocityMax);
  const max = Math.max(min + 0.01, s.velocityMax);
  return (v) => min + (max - min) * shape(Math.max(0, Math.min(1, v)));
}
