/**
 * Bus maestro de la Etapa 1: ganancia con headroom + limitador de seguridad
 * + analizador para el medidor. En la Etapa 5 se ampliará a buses de envío,
 * medición RMS/peak por pista y gain staging asistido.
 *
 * El limitador aquí es SOLO protección anti-clipping para tocar en directo;
 * no es (ni pretende ser) el limitador true-peak del auto-máster (Etapa 6).
 */
export class MasterBus {
  readonly input: GainNode;
  private limiter: DynamicsCompressorNode;
  private analyser: AnalyserNode;
  private buf: Float32Array<ArrayBuffer>;
  private meterSuspended = false;

  constructor(ctx: AudioContext) {
    this.input = ctx.createGain();
    this.input.gain.value = 0.9; // headroom

    this.limiter = ctx.createDynamicsCompressor();
    this.limiter.threshold.value = -3;
    this.limiter.knee.value = 0;
    this.limiter.ratio.value = 20;
    this.limiter.attack.value = 0.002;
    this.limiter.release.value = 0.15;

    this.analyser = ctx.createAnalyser();
    this.analyser.fftSize = 1024;
    this.buf = new Float32Array(this.analyser.fftSize);

    this.input.connect(this.limiter).connect(this.analyser).connect(ctx.destination);
  }

  /** Suspende la lectura del medidor cuando la UI está oculta (ahorro CPU). */
  suspendMeter(suspend: boolean): void {
    this.meterSuspended = suspend;
  }

  /** Pico y RMS instantáneos (lineal 0–1) del último bloque. */
  levels(): { peak: number; rms: number } {
    if (this.meterSuspended) return { peak: 0, rms: 0 };
    this.analyser.getFloatTimeDomainData(this.buf);
    let peak = 0;
    let sum = 0;
    for (let i = 0; i < this.buf.length; i++) {
      const a = Math.abs(this.buf[i]);
      if (a > peak) peak = a;
      sum += this.buf[i] * this.buf[i];
    }
    return { peak, rms: Math.sqrt(sum / this.buf.length) };
  }

  /** Reducción de ganancia actual del limitador (dB) → aviso de clipping. */
  gainReductionDb(): number {
    return this.limiter.reduction;
  }
}
