import type { MidiEvent } from "./types";
import { CC } from "./types";

/**
 * Estados por los que pasa una nota. Distinguimos explícitamente:
 *  - held:      tecla físicamente pulsada.
 *  - sustained: tecla liberada, sostenida por CC64.
 *  - sostenuto: tecla liberada, sostenida por CC66 (capturada al pisar el pedal).
 * Las notas en release o robadas dejan de estar en el mapa: su ciclo de vida
 * continúa dentro del motor (fase de release / voice stealing).
 */
export type NoteHoldState = "held" | "sustained" | "sostenuto";

export interface TrackedNote {
  voiceId: number;
  note: number;
  channel: number;
  velocity: number;
  state: NoteHoldState;
  /** true si además está capturada por sostenuto (puede solaparse con held). */
  inSostenuto: boolean;
  startedAt: number; // audioTime
}

/**
 * Lo que el tracker le pide al motor de audio. El motor no sabe nada de
 * pedales: recibe órdenes de voz ya resueltas. Esto mantiene la lógica de
 * pedal en UN solo sitio, idéntica para todos los motores futuros.
 */
export interface EngineSink {
  voiceOn(voiceId: number, note: number, velocity: number, when: number, channel: number): void;
  /**
   * releaseScale multiplica el tiempo de release del motor:
   * 1 = release normal; >1 = release alargado (medio pedal).
   */
  voiceRelease(voiceId: number, when: number, releaseScale: number, releaseVelocity: number): void;
  /** Corte inmediato (pánico / All Sound Off). */
  voiceKill(voiceId: number): void;
  controlChange(controller: number, value: number, when: number, channel: number): void;
  pitchBend(bend14: number, when: number, channel: number): void;
  channelPressure(value: number, when: number, channel: number): void;
  polyAftertouch(note: number, value: number, when: number, channel: number): void;
  allSoundOff(): void;
}

const key = (ch: number, note: number) => (ch << 8) | note;

export class NoteTracker {
  private notes = new Map<number, TrackedNote>();
  private nextVoiceId = 1;
  /** Valor continuo de CC64 por canal (0–127). */
  private sustain = new Array<number>(16).fill(0);
  /** Valor de CC67 (soft) por canal. */
  private soft = new Array<number>(16).fill(0);
  /** Umbral estándar: CC64 >= 64 → pedal pisado. */
  sustainThreshold = 64;
  /**
   * Timeout de seguridad en segundos. 0 = desactivado (por defecto):
   * un pad puede sonar minutos legítimamente. Configurable en Ajustes.
   */
  safetyTimeoutSec = 0;
  /** Transposición en semitonos aplicada a la entrada. */
  transpose = 0;
  /** Curva de velocidad: función 0–1 → 0–1. */
  velocityCurve: (v: number) => number = (v) => v;

  private onStateChange: (() => void) | null = null;

  constructor(
    private sink: EngineSink,
    private now: () => number,
  ) {}

  setStateListener(fn: () => void): void {
    this.onStateChange = fn;
  }

  /** Vista de solo lectura para la UI de diagnóstico. */
  activeNotes(): TrackedNote[] {
    return [...this.notes.values()];
  }

  sustainValue(ch = 0): number {
    return this.sustain[ch];
  }

  handle(ev: MidiEvent): void {
    const when = Math.max(ev.audioTime, this.now());
    switch (ev.kind) {
      case "noteOn":
        this.noteOn(ev.channel, ev.note!, ev.velocity!, when);
        break;
      case "noteOff":
        this.noteOff(ev.channel, ev.note!, ev.releaseVelocity ?? 64, when);
        break;
      case "controlChange":
        this.cc(ev.channel, ev.controller!, ev.value!, when);
        break;
      case "pitchBend":
        this.sink.pitchBend(ev.bend14!, when, ev.channel);
        break;
      case "channelPressure":
        this.sink.channelPressure(ev.value!, when, ev.channel);
        break;
      case "polyAftertouch":
        this.sink.polyAftertouch(ev.note!, ev.value!, when, ev.channel);
        break;
      // programChange / system / unknown: se conservan aguas arriba (grabación
      // futura); el motor de la Etapa 1 no los necesita.
    }
    this.checkSafetyTimeout();
    this.onStateChange?.();
  }

  private noteOn(ch: number, rawNote: number, rawVel: number, when: number): void {
    const note = clampNote(rawNote + this.transpose);
    if (note < 0) return;
    const k = key(ch, note);

    // Nota repetida sin Note Off intermedio (o retenida por pedal):
    // liberamos la voz anterior y creamos una nueva con ID propio.
    const existing = this.notes.get(k);
    if (existing) {
      this.sink.voiceRelease(existing.voiceId, when, 1, 64);
      this.notes.delete(k);
    }

    let vel = this.velocityCurve(rawVel / 127);
    // Soft pedal (una corda): reduce velocidad efectiva de forma continua.
    const softAmt = this.soft[ch] / 127;
    vel *= 1 - 0.35 * softAmt;
    vel = Math.max(1 / 127, Math.min(1, vel));

    const voiceId = this.nextVoiceId++;
    this.notes.set(k, {
      voiceId,
      note,
      channel: ch,
      velocity: vel,
      state: "held",
      inSostenuto: false,
      startedAt: when,
    });
    this.sink.voiceOn(voiceId, note, vel, when, ch);
  }

  private noteOff(ch: number, rawNote: number, relVel: number, when: number): void {
    const note = clampNote(rawNote + this.transpose);
    if (note < 0) return;
    const tracked = this.notes.get(key(ch, note));
    if (!tracked) return; // Note Off huérfano: ignorar con seguridad.

    if (tracked.inSostenuto) {
      // Capturada por sostenuto: sigue sonando hasta soltar CC66.
      tracked.state = "sostenuto";
      return;
    }
    if (this.sustain[ch] >= this.sustainThreshold) {
      // Pedal pisado: la nota pasa a sostenida, NO se libera.
      tracked.state = "sustained";
      return;
    }
    // Liberación normal, con medio pedal si CC64 está en zona parcial.
    this.releaseTracked(tracked, when, this.halfPedalScale(ch), relVel);
  }

  private cc(ch: number, controller: number, value: number, when: number): void {
    switch (controller) {
      case CC.SUSTAIN:
        this.sustainChange(ch, value, when);
        return; // El pedal no se reenvía al motor: ya está resuelto aquí.
      case CC.SOSTENUTO:
        this.sostenutoChange(ch, value, when);
        return;
      case CC.SOFT:
        this.soft[ch] = value;
        this.sink.controlChange(controller, value, when, ch);
        return;
      case CC.ALL_NOTES_OFF:
        // Según la norma MIDI, equivale a Note Off de todas las notas:
        // las notas siguen sujetas al pedal si está pisado.
        for (const t of [...this.notes.values()]) {
          if (t.channel === ch && t.state === "held") {
            this.noteOff(ch, t.note - this.transpose, 64, when);
          }
        }
        return;
      case CC.ALL_SOUND_OFF:
        this.allSoundOff(ch);
        return;
      case CC.RESET_CONTROLLERS:
        this.resetControllers(ch, when);
        return;
      default:
        this.sink.controlChange(controller, value, when, ch);
    }
  }

  /**
   * Cambio de CC64 con soporte de pedal continuo.
   * - Sube por encima del umbral: las notas pulsadas quedan protegidas
   *   (ya lo están: solo cambia qué ocurre en su Note Off).
   * - Baja del umbral: se liberan SOLO las notas sostenidas por pedal;
   *   las teclas físicamente pulsadas siguen sonando.
   * - Valores intermedios al soltar → release alargado (medio pedal).
   */
  private sustainChange(ch: number, value: number, when: number): void {
    const prev = this.sustain[ch];
    this.sustain[ch] = value;
    if (prev >= this.sustainThreshold && value < this.sustainThreshold) {
      const scale = this.halfPedalScale(ch);
      for (const t of [...this.notes.values()]) {
        if (t.channel === ch && t.state === "sustained") {
          this.releaseTracked(t, when, scale, 64);
        }
      }
    }
  }

  /** Escala de release según zona parcial del pedal (1 = normal, hasta ~4x). */
  private halfPedalScale(ch: number): number {
    const v = this.sustain[ch];
    if (v <= 0 || v >= this.sustainThreshold) return 1;
    return 1 + 3 * (v / this.sustainThreshold);
  }

  private sostenutoChange(ch: number, value: number, when: number): void {
    if (value >= 64) {
      // Captura las notas físicamente pulsadas EN ESTE instante.
      for (const t of this.notes.values()) {
        if (t.channel === ch && t.state === "held") t.inSostenuto = true;
      }
    } else {
      for (const t of [...this.notes.values()]) {
        if (t.channel !== ch || !t.inSostenuto) continue;
        t.inSostenuto = false;
        if (t.state === "sostenuto") {
          // Tecla ya soltada: ¿la recoge el sustain?
          if (this.sustain[ch] >= this.sustainThreshold) {
            t.state = "sustained";
          } else {
            this.releaseTracked(t, when, this.halfPedalScale(ch), 64);
          }
        }
        // Si sigue "held", no hay nada que hacer: la tecla manda.
      }
    }
  }

  private releaseTracked(t: TrackedNote, when: number, scale: number, relVel: number): void {
    this.notes.delete(key(t.channel, t.note));
    this.sink.voiceRelease(t.voiceId, when, scale, relVel / 127 || 0.5);
  }

  /** Corte inmediato de un canal (o todos con ch = -1). */
  allSoundOff(ch = -1): void {
    for (const t of [...this.notes.values()]) {
      if (ch === -1 || t.channel === ch) {
        this.notes.delete(key(t.channel, t.note));
        this.sink.voiceKill(t.voiceId);
      }
    }
    if (ch === -1) this.sink.allSoundOff();
    this.onStateChange?.();
  }

  resetControllers(ch: number, when: number): void {
    this.sustain[ch] = 0;
    this.soft[ch] = 0;
    this.sink.pitchBend(0, when, ch);
    this.sink.channelPressure(0, when, ch);
    this.sink.controlChange(CC.MODULATION, 0, when, ch);
    this.sink.controlChange(CC.EXPRESSION, 127, when, ch);
  }

  /**
   * Botón de pánico y limpieza tras desconexión, cambio de preset,
   * suspensión o pérdida de foco.
   */
  panic(): void {
    for (let ch = 0; ch < 16; ch++) this.resetControllers(ch, this.now());
    this.allSoundOff(-1);
  }

  /**
   * Al perder el foco o suspender la app NO cortamos el sonido (podrías estar
   * dejando sonar una cola a propósito), pero las teclas "pulsadas" dejan de
   * ser fiables: las pasamos a estado sostenido-por-seguridad y las liberamos
   * con release normal. Así jamás queda una nota atascada tras volver.
   */
  releasePhysicallyHeld(): void {
    const when = this.now();
    for (const t of [...this.notes.values()]) {
      if (t.state === "held" && !t.inSostenuto) {
        if (this.sustain[t.channel] >= this.sustainThreshold) {
          t.state = "sustained";
        } else {
          this.releaseTracked(t, when, 1, 0.5);
        }
      }
    }
    this.onStateChange?.();
  }

  private checkSafetyTimeout(): void {
    if (this.safetyTimeoutSec <= 0) return;
    const now = this.now();
    for (const t of [...this.notes.values()]) {
      if (now - t.startedAt > this.safetyTimeoutSec) {
        this.releaseTracked(t, now, 1, 0.5);
      }
    }
  }
}

function clampNote(n: number): number {
  return n >= 0 && n <= 127 ? n : -1;
}
