import { getAudioContext, resumeAudio } from "./audio/context";
import { MasterBus } from "./audio/masterBus";
import { SubtractiveEngine } from "./audio/engines/subtractive/engine";
import { FACTORY_PRESETS } from "./audio/engines/subtractive/presets";
import type { Engine, EnginePreset } from "./audio/engines/types";
import { MidiManager } from "./midi/manager";
import { NoteTracker } from "./midi/noteTracker";
import { loadSettings, saveSettings, buildVelocityCurve } from "./state/settings";
import { App } from "./ui/app";
import "./style.css";

const ctx = getAudioContext();
const master = new MasterBus(ctx);
const midi = new MidiManager(ctx);
const settings = loadSettings();

/**
 * Motor cargado bajo demanda: solo existe UN motor a la vez.
 * Cambiar de motor (Etapa 2) hará dispose() del actual y creará el nuevo,
 * liberando de verdad sus nodos y buffers.
 */
let engine: Engine | null = null;
let currentPreset: EnginePreset =
  FACTORY_PRESETS.find((p) => p.name === settings.presetName) ?? FACTORY_PRESETS[0];

function ensureEngine(): Engine {
  if (!engine) {
    engine = new SubtractiveEngine(ctx);
    engine.output.connect(master.input);
    engine.applyPreset(currentPreset);
  }
  return engine;
}

const tracker = new NoteTracker(
  {
    voiceOn: (id, n, v, w, ch) => ensureEngine().voiceOn(id, n, v, w, ch),
    voiceRelease: (id, w, s, rv) => engine?.voiceRelease(id, w, s, rv),
    voiceKill: (id) => engine?.voiceKill(id),
    controlChange: (c, v, w, ch) => engine?.controlChange(c, v, w, ch),
    pitchBend: (b, w, ch) => engine?.pitchBend(b, w, ch),
    channelPressure: (v, w, ch) => engine?.channelPressure(v, w, ch),
    polyAftertouch: (n, v, w, ch) => engine?.polyAftertouch(n, v, w, ch),
    allSoundOff: () => engine?.allSoundOff(),
  },
  () => ctx.currentTime,
);

function applySettings(): void {
  tracker.transpose = settings.transpose;
  tracker.safetyTimeoutSec = settings.safetyTimeoutSec;
  tracker.velocityCurve = buildVelocityCurve(settings);
  midi.channelFilter = settings.channel;
  midi.deviceFilter = settings.deviceId;
  midi.inputLatencyMs = settings.inputLatencyMs;
  saveSettings(settings);
}
applySettings();

midi.onEvent((ev) => tracker.handle(ev));

// Limpieza al desconectar un dispositivo: sus teclas "pulsadas" ya no son
// fiables → se liberan con release normal (jamás una nota atascada).
midi.onDevicesChanged((devs) => {
  if (devs.every((d) => d.state !== "connected")) tracker.releasePhysicallyHeld();
});

// Suspensión / pérdida de foco: liberar teclas pulsadas (no cortar colas).
document.addEventListener("visibilitychange", () => {
  if (document.visibilityState === "hidden") tracker.releasePhysicallyHeld();
});
window.addEventListener("pagehide", () => tracker.panic());

// El AudioContext exige un gesto de usuario para arrancar.
let resumed = false;
async function firstGesture(): Promise<void> {
  if (resumed) return;
  resumed = true;
  await resumeAudio();
  ensureEngine();
}
window.addEventListener("pointerdown", () => void firstGesture(), { once: true, capture: true });
window.addEventListener("keydown", () => void firstGesture(), { once: true, capture: true });

// ── Pruebas sin teclado (usan el mismo camino que el MIDI real) ────────────
function runTest(name: "chord" | "sequence" | "pedal" | "poly"): void {
  void firstGesture();
  const on = (note: number, vel: number, at: number) =>
    setTimeout(() => midi.inject({ kind: "noteOn", channel: 0, note, velocity: vel }), at);
  const off = (note: number, at: number) =>
    setTimeout(() => midi.inject({ kind: "noteOff", channel: 0, note, releaseVelocity: 64 }), at);
  const cc = (controller: number, value: number, at: number) =>
    setTimeout(() => midi.inject({ kind: "controlChange", channel: 0, controller, value }), at);

  switch (name) {
    case "chord":
      for (const n of [48, 55, 60, 64]) { on(n, 88, 0); off(n, 1600); }
      break;
    case "sequence": {
      const seq = [60, 63, 67, 70, 72, 70, 67, 63];
      seq.forEach((n, i) => { on(n, 60 + ((i * 13) % 60), i * 220); off(n, i * 220 + 200); });
      break;
    }
    case "pedal":
      // Nota + pedal → soltar tecla (debe seguir sonando) → soltar pedal.
      cc(64, 127, 0);
      on(60, 90, 100); off(60, 400);
      on(64, 90, 700); off(64, 1000);
      cc(64, 0, 2200);
      break;
    case "poly":
      for (let i = 0; i < 24; i++) { on(36 + i * 3, 70, i * 60); off(36 + i * 3, i * 60 + 2500); }
      break;
  }
}

// ── UI ─────────────────────────────────────────────────────────────────────
new App(document.getElementById("app")!, {
  midi,
  tracker,
  master,
  presets: FACTORY_PRESETS,
  settings,
  currentPreset: () => currentPreset,
  loadPreset: (p) => {
    // Cambio de preset: primero limpieza de voces (regla anti-nota-atascada),
    // conservando el estado de los pedales físicos.
    tracker.allSoundOff();
    currentPreset = p;
    settings.presetName = p.name;
    saveSettings(settings);
    ensureEngine().applyPreset(p);
  },
  onSettingsChanged: applySettings,
  onFirstGesture: () => void firstGesture(),
  runTest,
  voiceCount: () => engine?.voiceCount() ?? 0,
});

void midi.init();

// ── PWA: Service Worker con ruta relativa (compatible con GitHub Pages) ───
if ("serviceWorker" in navigator && !location.hostname.includes("localhost")) {
  window.addEventListener("load", () => {
    navigator.serviceWorker.register("./sw.js").catch((e) => {
      console.warn("Service Worker no registrado:", e);
    });
  });
}
