/**
 * Conversión estable entre el reloj de eventos MIDI (performance.now())
 * y el reloj de audio (AudioContext.currentTime).
 *
 * Los timestamps de MIDIMessageEvent usan la base de performance.now().
 * Para programar audio con precisión hay que traducirlos al reloj del
 * AudioContext. AudioContext.getOutputTimestamp() devuelve un par
 * (contextTime, performanceTime) muestreado simultáneamente; con varios
 * pares filtrados obtenemos un offset estable y sin saltos.
 */
export class ClockSync {
  private offsetSec = 0; // contextTime - performanceTime/1000
  private samples: number[] = [];
  private timer: number | null = null;

  constructor(private ctx: AudioContext) {
    this.sample();
  }

  start(): void {
    if (this.timer !== null) return;
    // Re-muestrear periódicamente: baratísimo y corrige deriva.
    this.timer = window.setInterval(() => this.sample(), 2000);
  }

  stop(): void {
    if (this.timer !== null) {
      clearInterval(this.timer);
      this.timer = null;
    }
  }

  private sample(): void {
    let ct: number, pt: number;
    const ts = this.ctx.getOutputTimestamp?.();
    if (ts && ts.contextTime !== undefined && ts.performanceTime !== undefined) {
      ct = ts.contextTime;
      pt = ts.performanceTime;
    } else {
      // Fallback: muestreo casi simultáneo (menos preciso, suficiente).
      pt = performance.now();
      ct = this.ctx.currentTime;
    }
    const off = ct - pt / 1000;
    this.samples.push(off);
    if (this.samples.length > 8) this.samples.shift();
    // Mediana: robusta frente a muestras tomadas en un frame ocupado.
    const sorted = [...this.samples].sort((a, b) => a - b);
    this.offsetSec = sorted[Math.floor(sorted.length / 2)];
  }

  /** Convierte un timestamp performance.now() (ms) a tiempo de audio (s). */
  toAudioTime(hrTimeMs: number): number {
    return hrTimeMs / 1000 + this.offsetSec;
  }
}
