/**
 * AudioContext único y compartido por toda la aplicación.
 * Nunca se crean/destruyen contextos por instrumento: los motores se
 * conectan y desconectan de este contexto.
 */
let ctx: AudioContext | null = null;

export function getAudioContext(): AudioContext {
  if (!ctx) {
    ctx = new AudioContext({
      latencyHint: "interactive",
      // sampleRate: se deja el nativo del dispositivo → evita resampleos.
    });
  }
  return ctx;
}

/** Debe llamarse desde un gesto de usuario (requisito de los navegadores). */
export async function resumeAudio(): Promise<void> {
  const c = getAudioContext();
  if (c.state !== "running") await c.resume();
}

export function audioInfo(): {
  state: string;
  sampleRate: number;
  baseLatency: number | null;
  outputLatency: number | null;
} {
  const c = getAudioContext();
  return {
    state: c.state,
    sampleRate: c.sampleRate,
    baseLatency: c.baseLatency ?? null,
    outputLatency: (c as AudioContext & { outputLatency?: number }).outputLatency ?? null,
  };
}
