import type { MidiManager } from "../midi/manager";

/**
 * Modo sin teclado físico: teclado táctil multitáctil + mapeo QWERTY.
 * Inyecta eventos por el MISMO camino que el MIDI real (MidiManager.inject),
 * de modo que ejercita tracker, pedales y motor exactamente igual.
 *
 * Velocidad táctil: posición vertical del dedo dentro de la tecla
 * (abajo = fuerte), el sustituto táctil más tocable en la práctica.
 */

const QWERTY: Record<string, number> = {
  KeyA: 0, KeyW: 1, KeyS: 2, KeyE: 3, KeyD: 4, KeyF: 5, KeyT: 6,
  KeyG: 7, KeyY: 8, KeyH: 9, KeyU: 10, KeyJ: 11, KeyK: 12, KeyO: 13,
  KeyL: 14, KeyP: 15,
};

export class TouchKeyboard {
  readonly el: HTMLElement;
  private baseNote = 48; // C3
  private pointers = new Map<number, number>(); // pointerId → nota
  private keysDown = new Set<string>();
  private sustainOn = false;
  private label!: HTMLElement;
  private sustainBtn!: HTMLButtonElement;

  constructor(private midi: MidiManager, private onFirstGesture: () => void) {
    this.el = document.createElement("div");
    this.el.className = "kb";
    this.render();
    this.bindQwerty();
  }

  private noteOn(note: number, velocity: number): void {
    this.onFirstGesture();
    this.midi.inject({ kind: "noteOn", channel: 0, note, velocity: Math.round(velocity * 126) + 1 });
  }

  private noteOff(note: number): void {
    this.midi.inject({ kind: "noteOff", channel: 0, note, releaseVelocity: 64 });
  }

  private setSustain(v: number): void {
    this.onFirstGesture();
    this.midi.inject({ kind: "controlChange", channel: 0, controller: 64, value: v });
  }

  private render(): void {
    this.el.innerHTML = "";

    const bar = document.createElement("div");
    bar.className = "kb-bar";

    const down = octaveBtn("−8va", () => this.shift(-12));
    const up = octaveBtn("+8va", () => this.shift(12));
    this.label = document.createElement("span");
    this.label.className = "kb-oct mono";

    this.sustainBtn = document.createElement("button");
    this.sustainBtn.className = "kb-sus";
    this.sustainBtn.textContent = "SUSTAIN";
    // Mantener pulsado = pedal pisado; toque corto = conmutar (latch).
    let pressT = 0;
    this.sustainBtn.addEventListener("pointerdown", (e) => {
      e.preventDefault();
      pressT = performance.now();
      if (!this.sustainOn) this.toggleSustain(true);
    });
    this.sustainBtn.addEventListener("pointerup", () => {
      if (performance.now() - pressT > 300) this.toggleSustain(false);
      // Toque corto: queda en latch; el siguiente toque lo suelta.
      else if (!this.sustainOn) this.toggleSustain(false);
    });

    bar.append(down, this.label, up, this.sustainBtn);
    this.el.append(bar);

    const keys = document.createElement("div");
    keys.className = "kb-keys";
    // Dos octavas: 14 blancas + negras superpuestas.
    const whiteSemis = [0, 2, 4, 5, 7, 9, 11];
    for (let oct = 0; oct < 2; oct++) {
      for (let i = 0; i < 7; i++) {
        keys.append(this.makeKey(oct * 12 + whiteSemis[i], false));
      }
    }
    const blackAfterWhite: Record<number, number> = { 0: 1, 1: 3, 3: 6, 4: 8, 5: 10 };
    for (let oct = 0; oct < 2; oct++) {
      for (const [wIdx, semi] of Object.entries(blackAfterWhite)) {
        const k = this.makeKey(oct * 12 + semi, true);
        k.style.left = `${((oct * 7 + Number(wIdx) + 0.68) / 14) * 100}%`;
        keys.append(k);
      }
    }
    this.el.append(keys);
    this.updateLabel();
  }

  private toggleSustain(on: boolean): void {
    this.sustainOn = on;
    this.setSustain(on ? 127 : 0);
    this.sustainBtn.classList.toggle("on", on);
  }

  private makeKey(offset: number, black: boolean): HTMLElement {
    const k = document.createElement("div");
    k.className = black ? "kb-key black" : "kb-key white";
    k.addEventListener("pointerdown", (e) => {
      e.preventDefault();
      const rect = k.getBoundingClientRect();
      const y = (e.clientY - rect.top) / rect.height; // 0 arriba, 1 abajo
      const vel = 0.25 + 0.75 * Math.max(0, Math.min(1, y));
      const note = this.baseNote + offset;
      this.pointers.set(e.pointerId, note);
      this.noteOn(note, vel);
      k.classList.add("down");
    });
    const release = (e: PointerEvent) => {
      const note = this.pointers.get(e.pointerId);
      if (note !== undefined) {
        this.pointers.delete(e.pointerId);
        this.noteOff(note);
      }
      k.classList.remove("down");
    };
    k.addEventListener("pointerup", release);
    k.addEventListener("pointercancel", release);
    k.addEventListener("pointerleave", release);
    return k;
  }

  private shift(semis: number): void {
    this.baseNote = Math.max(12, Math.min(84, this.baseNote + semis));
    this.updateLabel();
  }

  private updateLabel(): void {
    const oct = Math.floor(this.baseNote / 12) - 1;
    this.label.textContent = `C${oct}–C${oct + 2}`;
  }

  private bindQwerty(): void {
    window.addEventListener("keydown", (e) => {
      if (e.repeat) return;
      const target = e.target as HTMLElement;
      if (target.tagName === "INPUT" || target.tagName === "SELECT") return;
      if (e.code === "Space") {
        e.preventDefault();
        this.toggleSustain(true);
        return;
      }
      if (e.code === "KeyZ") return this.shift(-12);
      if (e.code === "KeyX") return this.shift(12);
      const off = QWERTY[e.code];
      if (off !== undefined && !this.keysDown.has(e.code)) {
        this.keysDown.add(e.code);
        this.noteOn(this.baseNote + off, 0.75);
      }
    });
    window.addEventListener("keyup", (e) => {
      if (e.code === "Space") {
        this.toggleSustain(false);
        return;
      }
      const off = QWERTY[e.code];
      if (off !== undefined && this.keysDown.delete(e.code)) {
        this.noteOff(this.baseNote + off);
      }
    });
    // Si la ventana pierde el foco, soltamos todas las teclas QWERTY.
    window.addEventListener("blur", () => {
      for (const code of this.keysDown) {
        const off = QWERTY[code];
        if (off !== undefined) this.noteOff(this.baseNote + off);
      }
      this.keysDown.clear();
      if (this.sustainOn) this.toggleSustain(false);
    });
  }
}

function octaveBtn(text: string, fn: () => void): HTMLButtonElement {
  const b = document.createElement("button");
  b.className = "kb-oct-btn";
  b.textContent = text;
  b.addEventListener("pointerdown", (e) => {
    e.preventDefault();
    fn();
  });
  return b;
}
