import type { Engine, EnginePreset } from "../types";
import { CC } from "../../../midi/types";

/**
 * Motor sustractivo (Etapa 1).
 *
 * Implementado con nodos nativos de Web Audio (OscillatorNode, BiquadFilter,
 * GainNode): el grafo nativo corre en el hilo de audio con latencia mínima y
 * coste de CPU muy bajo en móviles de gama media. Los motores con DSP propio
 * (AudioWorklet/WASM) llegan en la Etapa 2; este motor ya cumple la interfaz
 * común, así que convivirán sin cambios en el resto de la app.
 *
 * Por voz: osc1 + osc2 (detune/octava) → filtro LP con envolvente y
 * key-tracking → ADSR de amplitud. Global: LFO de vibrato (profundidad por
 * CC1), delay estéreo y reverb por convolución con IR sintetizada.
 */

interface Params {
  osc1Wave: OscillatorType;
  osc2Wave: OscillatorType;
  osc2DetuneCents: number;
  osc2Octave: number;
  oscMix: number; // 0 = solo osc1, 1 = solo osc2
  cutoffHz: number;
  resonanceQ: number;
  filterKeyTrack: number; // 0–1
  filterEnvAmount: number; // Hz añadidos por la envolvente
  filterVelAmount: number; // 0–1, cuánto abre la velocidad el filtro
  filterAttack: number;
  filterDecay: number;
  filterSustain: number; // 0–1
  ampAttack: number;
  ampDecay: number;
  ampSustain: number; // 0–1
  ampRelease: number;
  velToAmp: number; // 0–1
  vibratoRateHz: number;
  vibratoMaxCents: number;
  bendRangeSemis: number;
  gain: number;
  delayTime: number;
  delayFeedback: number;
  delayMix: number;
  reverbSeconds: number;
  reverbMix: number;
}

const DEFAULTS: Params = {
  osc1Wave: "sawtooth",
  osc2Wave: "sawtooth",
  osc2DetuneCents: 7,
  osc2Octave: 0,
  oscMix: 0.5,
  cutoffHz: 1200,
  resonanceQ: 0.8,
  filterKeyTrack: 0.5,
  filterEnvAmount: 2000,
  filterVelAmount: 0.6,
  filterAttack: 0.005,
  filterDecay: 0.35,
  filterSustain: 0.3,
  ampAttack: 0.004,
  ampDecay: 0.4,
  ampSustain: 0.7,
  ampRelease: 0.35,
  velToAmp: 0.8,
  vibratoRateHz: 5.2,
  vibratoMaxCents: 18,
  bendRangeSemis: 2,
  gain: 0.5,
  delayTime: 0.3,
  delayFeedback: 0.25,
  delayMix: 0,
  reverbSeconds: 1.8,
  reverbMix: 0.12,
};

interface Voice {
  id: number;
  note: number;
  osc1: OscillatorNode;
  osc2: OscillatorNode;
  filter: BiquadFilterNode;
  amp: GainNode;
  startedAt: number;
  releasedAt: number | null;
  peak: number; // nivel de sustain objetivo (para release proporcional)
}

export class SubtractiveEngine implements Engine {
  readonly id = "subtractive";
  readonly output: GainNode;

  private p: Params = { ...DEFAULTS };
  private polyphony = 16;
  private voices = new Map<number, Voice>();
  private dry: GainNode;
  private bus: GainNode;
  private volumeGain: GainNode; // CC7
  private expressionGain: GainNode; // CC11
  private vibratoOsc: OscillatorNode;
  private vibratoDepth: GainNode;
  private delay: DelayNode;
  private delayFb: GainNode;
  private delayMix: GainNode;
  private convolver: ConvolverNode;
  private reverbMix: GainNode;
  private bendCents = 0;
  private softDarken = 1; // CC67 oscurece ligeramente el filtro
  private disposed = false;

  constructor(private ctx: AudioContext) {
    this.bus = ctx.createGain();
    this.dry = ctx.createGain();
    this.volumeGain = ctx.createGain();
    this.expressionGain = ctx.createGain();
    this.output = ctx.createGain();

    // Vibrato global: un solo LFO modula el detune de todas las voces.
    this.vibratoOsc = ctx.createOscillator();
    this.vibratoOsc.frequency.value = this.p.vibratoRateHz;
    this.vibratoDepth = ctx.createGain();
    this.vibratoDepth.gain.value = 0; // controlado por CC1
    this.vibratoOsc.connect(this.vibratoDepth);
    this.vibratoOsc.start();

    // Delay estéreo simple con feedback.
    this.delay = ctx.createDelay(2);
    this.delayFb = ctx.createGain();
    this.delayMix = ctx.createGain();
    this.delay.connect(this.delayFb).connect(this.delay);
    this.delay.connect(this.delayMix);

    // Reverb por convolución con IR sintetizada (ruido con caída exponencial).
    this.convolver = ctx.createConvolver();
    this.reverbMix = ctx.createGain();
    this.convolver.connect(this.reverbMix);

    this.bus.connect(this.dry);
    this.bus.connect(this.delay);
    this.bus.connect(this.convolver);
    this.dry.connect(this.volumeGain);
    this.delayMix.connect(this.volumeGain);
    this.reverbMix.connect(this.volumeGain);
    this.volumeGain.connect(this.expressionGain).connect(this.output);

    this.applyGlobalParams();
  }

  applyPreset(preset: EnginePreset): void {
    this.p = { ...DEFAULTS, ...(preset.parameters as Partial<Params>), ...(preset.effects as Partial<Params>) };
    this.polyphony = Math.max(1, Math.min(48, preset.polyphony || 16));
    this.applyGlobalParams();
  }

  private applyGlobalParams(): void {
    const t = this.ctx.currentTime;
    this.output.gain.setTargetAtTime(this.p.gain, t, 0.02);
    this.vibratoOsc.frequency.setTargetAtTime(this.p.vibratoRateHz, t, 0.02);
    this.delay.delayTime.setTargetAtTime(this.p.delayTime, t, 0.02);
    this.delayFb.gain.setTargetAtTime(this.p.delayFeedback, t, 0.02);
    this.delayMix.gain.setTargetAtTime(this.p.delayMix, t, 0.02);
    this.reverbMix.gain.setTargetAtTime(this.p.reverbMix, t, 0.02);
    this.convolver.buffer = makeImpulseResponse(this.ctx, this.p.reverbSeconds);
  }

  voiceCount(): number {
    return this.voices.size;
  }

  // ── EngineSink ───────────────────────────────────────────────────────────

  voiceOn(voiceId: number, note: number, velocity: number, when: number, _ch: number): void {
    if (this.disposed) return;
    if (this.voices.size >= this.polyphony) this.stealVoice(when);

    const p = this.p;
    const freq = midiToHz(note);
    const osc1 = this.ctx.createOscillator();
    const osc2 = this.ctx.createOscillator();
    osc1.type = p.osc1Wave;
    osc2.type = p.osc2Wave;
    osc1.frequency.value = freq;
    osc2.frequency.value = freq * Math.pow(2, p.osc2Octave);
    osc1.detune.value = this.bendCents;
    osc2.detune.value = p.osc2DetuneCents + this.bendCents;
    this.vibratoDepth.connect(osc1.detune);
    this.vibratoDepth.connect(osc2.detune);

    const g1 = this.ctx.createGain();
    const g2 = this.ctx.createGain();
    g1.gain.value = Math.cos((p.oscMix * Math.PI) / 2); // equal-power
    g2.gain.value = Math.sin((p.oscMix * Math.PI) / 2);

    const filter = this.ctx.createBiquadFilter();
    filter.type = "lowpass";
    filter.Q.value = p.resonanceQ;
    // Cutoff base con key-tracking + apertura por velocidad + soft pedal.
    const keyTrack = Math.pow(freq / 261.63, p.filterKeyTrack);
    const velOpen = 1 - p.filterVelAmount * (1 - velocity);
    const base = clampHz(p.cutoffHz * keyTrack * velOpen * this.softDarken);
    const envPeak = clampHz(base + p.filterEnvAmount * velocity * this.softDarken);
    const envSus = clampHz(base + p.filterEnvAmount * velocity * p.filterSustain);
    const fc = filter.frequency;
    fc.setValueAtTime(base, when);
    fc.linearRampToValueAtTime(envPeak, when + Math.max(0.001, p.filterAttack));
    fc.setTargetAtTime(envSus, when + Math.max(0.001, p.filterAttack), Math.max(0.01, p.filterDecay / 3));

    const amp = this.ctx.createGain();
    const peak = (0.18 + 0.82 * velocity * p.velToAmp) * 0.35; // headroom
    const sus = peak * p.ampSustain;
    amp.gain.setValueAtTime(0, when);
    amp.gain.linearRampToValueAtTime(peak, when + Math.max(0.001, p.ampAttack));
    amp.gain.setTargetAtTime(sus, when + Math.max(0.001, p.ampAttack), Math.max(0.01, p.ampDecay / 3));

    osc1.connect(g1).connect(filter);
    osc2.connect(g2).connect(filter);
    filter.connect(amp).connect(this.bus);
    osc1.start(when);
    osc2.start(when);

    this.voices.set(voiceId, {
      id: voiceId,
      note,
      osc1,
      osc2,
      filter,
      amp,
      startedAt: when,
      releasedAt: null,
      peak: sus,
    });
  }

  voiceRelease(voiceId: number, when: number, releaseScale: number, _relVel: number): void {
    const v = this.voices.get(voiceId);
    if (!v) return;
    v.releasedAt = when;
    const rel = Math.max(0.01, this.p.ampRelease * releaseScale);
    const g = v.amp.gain;
    g.cancelScheduledValues(when);
    // setTargetAtTime desde el valor actual → sin clics.
    g.setTargetAtTime(0, when, rel / 4);
    v.filter.frequency.setTargetAtTime(
      clampHz(this.p.cutoffHz * 0.5),
      when,
      rel / 3,
    );
    const stopAt = when + rel * 2 + 0.1;
    v.osc1.stop(stopAt);
    v.osc2.stop(stopAt);
    v.osc1.onended = () => this.destroyVoice(voiceId);
  }

  voiceKill(voiceId: number): void {
    const v = this.voices.get(voiceId);
    if (!v) return;
    const t = this.ctx.currentTime;
    v.amp.gain.cancelScheduledValues(t);
    v.amp.gain.setTargetAtTime(0, t, 0.008); // fade de 8 ms: sin clic
    try {
      v.osc1.stop(t + 0.05);
      v.osc2.stop(t + 0.05);
    } catch {
      /* ya paradas */
    }
    v.osc1.onended = () => this.destroyVoice(voiceId);
  }

  private destroyVoice(voiceId: number): void {
    const v = this.voices.get(voiceId);
    if (!v) return;
    this.voices.delete(voiceId);
    try {
      this.vibratoDepth.disconnect(v.osc1.detune);
      this.vibratoDepth.disconnect(v.osc2.detune);
    } catch { /* ok */ }
    v.osc1.disconnect();
    v.osc2.disconnect();
    v.filter.disconnect();
    v.amp.disconnect();
  }

  /**
   * Robo de voces: primero la voz más antigua ya en release; si no hay,
   * la nota más antigua. Con fade rápido para evitar clics.
   */
  private stealVoice(when: number): void {
    let candidate: Voice | null = null;
    for (const v of this.voices.values()) {
      if (v.releasedAt !== null && (!candidate || v.releasedAt < candidate.releasedAt!)) {
        candidate = v;
      }
    }
    if (!candidate) {
      for (const v of this.voices.values()) {
        if (!candidate || v.startedAt < candidate.startedAt) candidate = v;
      }
    }
    if (candidate) {
      void when;
      this.voiceKill(candidate.id);
      this.voices.delete(candidate.id);
    }
  }

  controlChange(controller: number, value: number, when: number, _ch: number): void {
    const v = value / 127;
    switch (controller) {
      case CC.MODULATION:
        this.vibratoDepth.gain.setTargetAtTime(this.p.vibratoMaxCents * v, when, 0.03);
        break;
      case CC.VOLUME:
        this.volumeGain.gain.setTargetAtTime(v * v, when, 0.03); // curva cuadrática
        break;
      case CC.EXPRESSION:
        this.expressionGain.gain.setTargetAtTime(v * v, when, 0.02);
        break;
      case CC.SOFT:
        // Una corda: además de reducir velocidad (tracker), oscurece el timbre.
        this.softDarken = 1 - 0.3 * v;
        break;
      case CC.BREATH:
        this.expressionGain.gain.setTargetAtTime(0.3 + 0.7 * v, when, 0.02);
        break;
    }
  }

  pitchBend(bend14: number, when: number, _ch: number): void {
    this.bendCents = (bend14 / 8192) * this.p.bendRangeSemis * 100;
    for (const v of this.voices.values()) {
      v.osc1.detune.setTargetAtTime(this.bendCents, when, 0.01);
      v.osc2.detune.setTargetAtTime(this.p.osc2DetuneCents + this.bendCents, when, 0.01);
    }
  }

  channelPressure(value: number, when: number, _ch: number): void {
    // Aftertouch de canal → vibrato (además del mod wheel).
    const v = value / 127;
    if (v > 0) {
      this.vibratoDepth.gain.setTargetAtTime(this.p.vibratoMaxCents * v, when, 0.05);
    }
  }

  polyAftertouch(note: number, value: number, when: number, _ch: number): void {
    // Aftertouch polifónico → abre el filtro de esa nota.
    for (const v of this.voices.values()) {
      if (v.note === note && v.releasedAt === null) {
        const extra = 1 + (value / 127) * 1.5;
        v.filter.frequency.setTargetAtTime(
          clampHz(this.p.cutoffHz * extra),
          when,
          0.04,
        );
      }
    }
  }

  allSoundOff(): void {
    for (const id of [...this.voices.keys()]) this.voiceKill(id);
  }

  dispose(): void {
    this.disposed = true;
    this.allSoundOff();
    this.vibratoOsc.stop();
    for (const n of [
      this.bus, this.dry, this.delay, this.delayFb, this.delayMix,
      this.convolver, this.reverbMix, this.volumeGain, this.expressionGain,
      this.vibratoDepth, this.output,
    ]) {
      n.disconnect();
    }
    this.convolver.buffer = null; // libera el AudioBuffer de la IR
    this.voices.clear();
  }
}

function midiToHz(note: number): number {
  return 440 * Math.pow(2, (note - 69) / 12);
}

function clampHz(hz: number): number {
  return Math.max(30, Math.min(18000, hz));
}

/** IR estéreo sintetizada: ruido decorrelacionado con caída exponencial. */
function makeImpulseResponse(ctx: BaseAudioContext, seconds: number): AudioBuffer {
  const len = Math.max(1, Math.floor(ctx.sampleRate * seconds));
  const buf = ctx.createBuffer(2, len, ctx.sampleRate);
  for (let c = 0; c < 2; c++) {
    const d = buf.getChannelData(c);
    for (let i = 0; i < len; i++) {
      const t = i / len;
      d[i] = (Math.random() * 2 - 1) * Math.pow(1 - t, 2.4) * 0.5;
    }
  }
  return buf;
}
