/**
 * Tipos MIDI de Onda.
 *
 * Principio: NUNCA se pierde información. Cada evento conserva sus bytes
 * crudos (`raw`) además de la vista interpretada, de modo que mensajes no
 * reconocidos hoy puedan aprovecharse en versiones futuras (grabación,
 * exportación SMF, etc.).
 */

export type MidiEventKind =
  | "noteOn"
  | "noteOff"
  | "polyAftertouch"
  | "controlChange"
  | "programChange"
  | "channelPressure"
  | "pitchBend"
  | "system"
  | "unknown";

export interface MidiEvent {
  kind: MidiEventKind;
  /** Bytes crudos completos del mensaje. */
  raw: Uint8Array;
  /** Canal 0–15, o -1 para mensajes de sistema. */
  channel: number;
  /** Timestamp original del navegador (base performance.now()). */
  hrTime: number;
  /** Timestamp convertido al reloj de audio (AudioContext.currentTime). */
  audioTime: number;
  /** Nota 0–127 (noteOn/noteOff/polyAftertouch). */
  note?: number;
  /** Velocidad de pulsación 1–127 (noteOn). */
  velocity?: number;
  /** Velocidad de liberación 0–127 si el dispositivo la transmite (noteOff). */
  releaseVelocity?: number;
  /** Número de controlador (controlChange). */
  controller?: number;
  /** Valor 0–127 (CC, channelPressure, polyAftertouch, programChange). */
  value?: number;
  /** Pitch bend con resolución completa de 14 bits: -8192…+8191. */
  bend14?: number;
  /** ID del dispositivo de origen. */
  deviceId: string;
}

/** Controladores con semántica conocida por la app. */
export const CC = {
  MODULATION: 1,
  BREATH: 2,
  VOLUME: 7,
  PAN: 10,
  EXPRESSION: 11,
  BANK_MSB: 0,
  BANK_LSB: 32,
  SUSTAIN: 64,
  SOSTENUTO: 66,
  SOFT: 67,
  ALL_SOUND_OFF: 120,
  RESET_CONTROLLERS: 121,
  ALL_NOTES_OFF: 123,
} as const;

export interface MidiDeviceInfo {
  id: string;
  name: string;
  manufacturer: string;
  state: "connected" | "disconnected";
}

/**
 * Registro de qué está transmitiendo realmente el dispositivo.
 * No asumimos nada: se detecta observando el tráfico.
 */
export interface DeviceCapabilities {
  sendsReleaseVelocity: boolean;
  sendsChannelPressure: boolean;
  sendsPolyAftertouch: boolean;
  sendsPitchBend: boolean;
  /** CCs vistos → último valor recibido. */
  seenControllers: Map<number, number>;
  /** Valores de CC64 distintos de 0/127 → pedal continuo (medio pedal). */
  continuousSustain: boolean;
  channelsSeen: Set<number>;
}

export function newCapabilities(): DeviceCapabilities {
  return {
    sendsReleaseVelocity: false,
    sendsChannelPressure: false,
    sendsPolyAftertouch: false,
    sendsPitchBend: false,
    seenControllers: new Map(),
    continuousSustain: false,
    channelsSeen: new Set(),
  };
}
